  1	import React, { FC, useMemo, useState } from 'react';
  2	
  3	import useDeepCompareMemoize from '@kubevirt-utils/hooks/useDeepCompareMemoize/useDeepCompareMemoize';
  4	import { useKubevirtTranslation } from '@kubevirt-utils/hooks/useKubevirtTranslation';
  5	import {
  6	  ColumnLayout,
  7	  FilterValue,
  8	  K8sResourceCommon,
  9	  OnFilterChange,
 10	  RowFilter,
 11	} from '@openshift-console/dynamic-plugin-sdk';
 12	import {
 13	  SelectOption,
 14	  Toolbar,
 15	  ToolbarContent,
 16	  ToolbarFilter,
 17	  ToolbarItem,
 18	  ToolbarToggleGroup,
 19	} from '@patternfly/react-core';
 20	import { FilterIcon } from '@patternfly/react-icons';
 21	
 22	import ColumnManagement from '../ColumnManagementModal/ColumnManagement';
 23	import FormPFSelect from '../FormPFSelect/FormPFSelect';
 24	
 25	import useListPageFiltersMethods from './hooks/useListPageFiltersMethods';
 26	import { useRowFiltersParameters } from './hooks/useRowFiltersParametersType';
 27	import { useSearchFiltersParameters } from './hooks/useSearchFiltersParameters';
 28	import AutocompleteInput from './AutocompleteInput';
 29	import {
 30	  STATIC_SEARCH_FILTERS,
 31	  STATIC_SEARCH_FILTERS_LABELS,
 32	  STATIC_SEARCH_FILTERS_PLACEHOLDERS,
 33	} from './constants';
 34	import RowFilters from './RowFilters';
 35	import SearchFilter from './SearchFilter';
 36	import {
 37	  Filter,
 38	  FilterKeys,
 39	  generateRowFilters,
 40	  getFiltersData,
 41	  getInitialSearchText,
 42	  getInitialSearchType,
 43	  getSearchTextPlaceholder,
 44	} from './utils';
 45	
 46	type ListPageFilterProps = {
 47	  columnLayout?: ColumnLayout;
 48	  data?: K8sResourceCommon[];
 49	  hideColumnManagement?: boolean;
 50	  hideLabelFilter?: boolean;
 51	  hideNameLabelFilters?: boolean;
 52	  loaded?: boolean;
 53	  nameFilterPlaceholder?: string;
 54	  onFilterChange?: OnFilterChange;
 55	  rowFilters?: RowFilter[];
 56	  searchFilters?: RowFilter[];
 57	};
 58	
 59	const ListPageFilter: FC<ListPageFilterProps> = ({
 60	  columnLayout,
 61	  data,
 62	  hideColumnManagement,
 63	  hideLabelFilter,
 64	  hideNameLabelFilters,
 65	  loaded,
 66	  nameFilterPlaceholder,
 67	  onFilterChange,
 68	  rowFilters,
 69	  searchFilters = [],
 70	}) => {
 71	  const { t } = useKubevirtTranslation();
 72	
 73	  const toolbarFilters = rowFilters?.filter((filter) => 'items' in filter);
 74	
 75	  // Generate rowFilter items and counts. Memoize to minimize re-renders.
 76	  const generatedRowFilters = useDeepCompareMemoize(generateRowFilters(toolbarFilters ?? [], data));
 77	
 78	  // Reduce generatedRowFilters once and memoize
 79	  const [filters, filtersNameMap, filterKeys] = useMemo<[Filter, FilterKeys, FilterKeys, string[]]>(
 80	    () => getFiltersData(generatedRowFilters),
 81	    [generatedRowFilters],
 82	  );
 83	
 84	  const [selectedRowFilters, onRowFilterSearchParamChange] = useRowFiltersParameters({
 85	    filterKeys,
 86	    filters,
 87	  });
 88	
 89	  const textFilters = useSearchFiltersParameters(searchFilters);
 90	
 91	  const filterDropdownItems: Record<string, string> = {
 92	    ...searchFilters.reduce(
 93	      (acc, filter) => ({
 94	        ...acc,
 95	        [filter.type]: filter.filterGroupName,
 96	      }),
 97	      {},
 98	    ),
 99	    ...(!hideLabelFilter && !hideNameLabelFilters ? { labels: t('Label') } : {}),
100	    ...(!hideNameLabelFilters ? { name: t('Name') } : {}),
101	  };
102	
103	  const [searchType, setSearchType] = useState<string>(
104	    getInitialSearchType(searchFilters, textFilters, filterDropdownItems),
105	  );
106	
107	  const [searchInputText, setSearchInputText] = useState<string>(
108	    getInitialSearchText(textFilters, searchType),
109	  );
110	
111	  const onSelect = (_, value: string) => {
112	    setSearchInputText(getInitialSearchText(textFilters, value));
113	    setSearchType(value);
114	  };
115	
116	  const applyFilters = (type: string, input: FilterValue) => onFilterChange?.(type, input);
117	
118	  const { applyTextFilters, applyTextFiltersWithDebounce, clearAll, updateRowFilterSelected } =
119	    useListPageFiltersMethods({
120	      applyFilters,
121	      generatedRowFilters,
122	      onRowFilterSearchParamChange,
123	      searchFilters,
124	      selectedRowFilters,
125	      setSearchInputText,
126	    });
127	
128	  if (!loaded) return null;
129	
130	  const selectedSearchFilter = searchFilters?.find((f) => f.type === searchType);
131	
132	  const filterDropdownKeys = Object.keys(filterDropdownItems);
133	
134	  return (
135	    <Toolbar
136	      className="co-toolbar-no-padding pf-m-toggle-group-container"
137	      clearAllFilters={clearAll}
138	      clearFiltersButtonText={t('Clear all filters')}
139	      data-test="filter-toolbar"
140	      id="filter-toolbar"
141	    >
142	      <ToolbarContent>
143	        <ToolbarToggleGroup breakpoint="md" toggleIcon={<FilterIcon />}>
144	          <RowFilters
145	            filters={filters}
146	            filtersNameMap={filtersNameMap}
147	            generatedRowFilters={generatedRowFilters}
148	            rowFilters={toolbarFilters}
149	            selectedRowFilters={selectedRowFilters}
150	            updateRowFilterSelected={updateRowFilterSelected}
151	          />
152	          {filterDropdownKeys.length !== 0 && (
153	            <ToolbarItem className="co-filter-search--full-width">
154	              <ToolbarFilter
155	                deleteLabel={(category, chip: string) => {
156	                  const newLabels = textFilters?.labels?.filter((label) => label !== chip);
157	                  applyTextFilters(STATIC_SEARCH_FILTERS.labels, newLabels.join(','));
158	                }}
159	                deleteLabelGroup={() => {
160	                  applyTextFilters(STATIC_SEARCH_FILTERS.labels);
161	                }}
162	                categoryName={STATIC_SEARCH_FILTERS_LABELS.labels}
163	                chips={textFilters.labels ?? []}
164	              >
165	                {searchFilters.map((filter) => (
166	                  <ToolbarFilter
167	                    deleteLabel={() => {
168	                      applyTextFilters(filter.type);
169	                      searchType === filter.type && setSearchInputText('');
170	                    }}
171	                    categoryName={filter.filterGroupName}
172	                    labels={textFilters[filter.type] ? [textFilters[filter.type]] : []}
173	                    key={filter.type}
174	                  >
175	                    <></>
176	                  </ToolbarFilter>
177	                ))}
178	
179	                <ToolbarFilter
180	                  deleteLabel={() => {
181	                    applyTextFilters('name');
182	                    searchType === STATIC_SEARCH_FILTERS.name && setSearchInputText('');
183	                  }}
184	                  categoryName={t('Name')}
185	                  labels={textFilters.name ? [textFilters.name] : []}
186	                >
187	                  <div className="pf-v6-c-input-group co-filter-group">
188	                    {filterDropdownKeys.length > 1 && (
189	                      <FormPFSelect
190	                        onSelect={onSelect}
191	                        selected={searchType}
192	                        selectedLabel={filterDropdownItems?.[searchType]}
193	                      >
194	                        {filterDropdownKeys.map((key) => (
195	                          <SelectOption key={key} value={key}>
196	                            {filterDropdownItems?.[key]}
197	                          </SelectOption>
198	                        ))}
199	                      </FormPFSelect>
200	                    )}
201	
202	                    {searchType === STATIC_SEARCH_FILTERS.labels ? (
203	                      <AutocompleteInput
204	                        onSuggestionSelect={(selected) => {
205	                          const newLabels = new Set([...textFilters.labels, selected]);
206	                          applyTextFilters(
207	                            STATIC_SEARCH_FILTERS.labels,
208	                            Array.from(newLabels).join(','),
209	                          );
210	                          setSearchInputText('');
211	                        }}
212	                        className="co-text-node"
213	                        data={data}
214	                        placeholder={STATIC_SEARCH_FILTERS_PLACEHOLDERS.labels}
215	                        setTextValue={setSearchInputText}
216	                        textValue={searchInputText}
217	                      />
218	                    ) : (
219	                      <SearchFilter
220	                        onChange={(_, newSearchInput: string) => {
221	                          setSearchInputText(newSearchInput);
222	                          applyTextFiltersWithDebounce(searchType, newSearchInput);
223	                        }}
224	                        placeholder={getSearchTextPlaceholder(
225	                          searchType,
226	                          selectedSearchFilter,
227	                          nameFilterPlaceholder,
228	                        )}
229	                        data-test={`${searchType}-filter-input`}
230	                        value={searchInputText || ''}
231	                      />
232	                    )}
233	                  </div>
234	                </ToolbarFilter>
235	              </ToolbarFilter>
236	            </ToolbarItem>
237	          )}
238	        </ToolbarToggleGroup>
239	        <ColumnManagement columnLayout={columnLayout} hideColumnManagement={hideColumnManagement} />
240	      </ToolbarContent>
241	    </Toolbar>
242	  );
243	};
244	
245	export default ListPageFilter;

