143	      <ToolbarContent>
144	        <ToolbarToggleGroup breakpoint="md" toggleIcon={<FilterIcon />}>
145	          <RowFilters
146	            filters={filters}
147	            filtersNameMap={filtersNameMap}
148	            generatedRowFilters={generatedRowFilters}
149	            rowFilters={toolbarFilters}
150	            selectedRowFilters={selectedRowFilters}
151	            updateRowFilterSelected={updateRowFilterSelected}
152	          />
153	          {filterDropdownKeys.length !== 0 && (
154	            <ToolbarItem className="co-filter-search--full-width">
155	              <div className="pf-v6-c-input-group co-filter-group">
156	                {filterDropdownKeys.length > 1 && (
157	                  <FormPFSelect
158	                    onSelect={onSelect}
159	                    selected={searchType}
160	                    selectedLabel={filterDropdownItems?.[searchType]}
161	                  >
162	                    <SelectList>
163	                      {filterDropdownKeys.map((key) => (
164	                        <SelectOption key={key} value={key}>
165	                          {filterDropdownItems?.[key]}
166	                        </SelectOption>
167	                      ))}
168	                    </SelectList>
169	                  </FormPFSelect>
170	                )}
171	
172	                {searchType === STATIC_SEARCH_FILTERS.labels ? (
173	                  <AutocompleteInput
174	                    onSuggestionSelect={(selected) => {
175	                      const newLabels = new Set([...textFilters.labels, selected]);
176	                      applyTextFilters(
177	                        STATIC_SEARCH_FILTERS.labels,
178	                        Array.from(newLabels).join(','),
179	                      );
180	                      setSearchInputText('');
181	                    }}
182	                    className="co-text-node"
183	                    data={data}
184	                    placeholder={STATIC_SEARCH_FILTERS_PLACEHOLDERS.labels}
185	                    setTextValue={setSearchInputText}
186	                    textValue={searchInputText}
187	                  />
188	                ) : (
189	                  <SearchFilter
190	                    onChange={(_, newSearchInput: string) => {
191	                      setSearchInputText(newSearchInput);
192	                      applyTextFiltersWithDebounce(searchType, newSearchInput);
193	                    }}
194	                    placeholder={getSearchTextPlaceholder(
195	                      searchType,
196	                      selectedSearchFilter,
197	                      nameFilterPlaceholder,
198	                    )}
199	                    data-test={`${searchType}-filter-input`}
200	                    value={searchInputText || ''}
201	                  />
202	                )}
203	              </div>
204	            </ToolbarItem>
205	          )}
206	        </ToolbarToggleGroup>
207	        <ToolbarFilter
208	          deleteLabel={(category, chip: string) => {
209	            const newLabels = textFilters?.labels?.filter((label) => label !== chip);
210	            applyTextFilters(STATIC_SEARCH_FILTERS.labels, newLabels.join(','));
211	          }}
212	          deleteLabelGroup={() => {
213	            applyTextFilters(STATIC_SEARCH_FILTERS.labels);
214	          }}
215	          categoryName={STATIC_SEARCH_FILTERS_LABELS.labels}
216	          labels={textFilters.labels ?? []}
217	        />
218	        {searchFilters.map((filter) => (
219	          <ToolbarFilter
220	            deleteLabel={() => {
221	              applyTextFilters(filter.type);
222	              searchType === filter.type && setSearchInputText('');
223	            }}
224	            categoryName={filter.filterGroupName}
225	            labels={textFilters[filter.type] ? [textFilters[filter.type]] : []}
226	            key={filter.type}
227	          />
228	        ))}
229	        <ToolbarFilter
230	          deleteLabel={() => {
231	            applyTextFilters('name');
232	            searchType === STATIC_SEARCH_FILTERS.name && setSearchInputText('');
233	          }}
234	          categoryName={t('Name')}
235	          labels={textFilters.name ? [textFilters.name] : []}
236	        />
237	        <ColumnManagement columnLayout={columnLayout} hideColumnManagement={hideColumnManagement} />
238	      </ToolbarContent>
239	    </Toolbar>
240	  );
241	};
242	
243	export default ListPageFilter;
